+        /// <summary>
+        /// PS-69087 #73 — harden <c>StoredFile.Store</c> / <c>StoredFile.StoreAndKeepOriginalFile</c>
+        /// coverage with explicit FileShare-side assertions on the upload-dir and FMSDirectory
+        /// side effects.
+        /// <para>
+        /// <see cref="StoredFile.Store"/> moves the source out of the upload dir into FMS, while
+        /// <see cref="StoredFile.StoreAndKeepOriginalFile"/> copies into FMS and leaves the source untouched.
+        /// </para>
+        /// </summary>
+        [TestMethod]
+        public void StoreAndKeepOriginalFile_CopiesToFMS_AndStorePathMovesFromUploadDir()
+        {
+            var requestedBy = GenerateRequestedByProject();
+            var fmsDirectory = new ProjectSightDMSService(requestedBy).GetFMSDirectory();
+            var uploadDirectory = GetWebFileUploadDirectory(ContextPortfolioId);
+
+            var keepStagedPath = StageFileInUploadDirectory(uploadDirectory, FILE_TO_UPLOAD, out var keepUploadFile);
+            var moveStagedPath = StageFileInUploadDirectory(uploadDirectory, FILE_TO_UPLOAD, out var moveUploadFile);
+
+            try
+            {
+                File.Exists(keepStagedPath).Should().BeTrue("staging precondition for StoreAndKeepOriginalFile");
+                File.Exists(moveStagedPath).Should().BeTrue("staging precondition for Store");
+
+                var keptStoredFile = StoredFile.StoreAndKeepOriginalFile(fmsDirectory, keepUploadFile);
+                var movedStoredFile = StoredFile.Store(fmsDirectory, moveUploadFile);
+
+                keptStoredFile.Should().NotBeNull();
+                movedStoredFile.Should().NotBeNull();
+
+                using (new AssertionScope())
+                {
+                    File.Exists(keptStoredFile.StoredFileName).Should().BeTrue("StoreAndKeepOriginalFile must produce the FMS copy");
+                    File.Exists(keepStagedPath).Should().BeTrue("StoreAndKeepOriginalFile must leave the original staged file in place");
+
+                    File.Exists(movedStoredFile.StoredFileName).Should().BeTrue("Store must produce the FMS copy");
+                    File.Exists(moveStagedPath).Should().BeFalse("Store must remove the original staged file from the upload directory");
+                }
+            }
+            finally
+            {
+                Global.KillAFile(keepStagedPath, true);
+                Global.KillAFile(moveStagedPath, true);
+                Global.KillAFile(Path.Combine(fmsDirectory, keepUploadFile.FileGuid()), true);
+                Global.KillAFile(Path.Combine(fmsDirectory, moveUploadFile.FileGuid()), true);
+            }
+        }
+
+        private static string StageFileInUploadDirectory(string uploadDirectory, TestFiles symbolicName, out UploadFile uploadFile)
+        {
+            var fileGuid = Guid.NewGuid();
+            var stagedName = Global.CreateFileGUIDFromGUID(fileGuid);
+            var stagedPath = Path.Combine(uploadDirectory, stagedName);
+
+            File.Copy(GetFilePath(symbolicName), stagedPath, overwrite: true);
+
+            uploadFile = new UploadFile
+            {
+                GUID = fileGuid.ToString(),
+                ServerFileName = stagedPath,
+                Name = GetFileName(symbolicName),
+                FileType = Path.GetExtension(GetFileName(symbolicName))
+            };
+
+            return stagedPath;
+        }
     }
 }

